sql:
SELECT peaks.name, images.image_url
FROM peaks
INNER JOIN images ON peaks.image_url = images.image_url;

SELECT name, difficulty
FROM (
  SELECT name, difficulty, RANK() OVER (ORDER BY difficulty DESC) AS difficulty_rank
  FROM peaks
)
WHERE difficulty_rank <= 5;

SELECT peaks.name, images.image_url 
FROM peaks 
INNER JOIN images ON peaks.peak_id = images.peak_id;

SELECT location_id, AVG(difficulty) AS avg_difficulty
FROM peaks
GROUP BY location_id;

SELECT l.location_name, p.name
FROM locations l
LEFT JOIN peaks p ON l.location_id = p.location_id;

external_knowledge:
Comprehensive ratings refer to average difficulty, scenery, and experience ratings; These ratings are based on a scale of 1 to 5, with 5 being the highest; 
A peak is considered to be any mountain or hill that has been reviewed and rated in the database; 
Reviews are considered to be any written feedback or comments left by users about a particular peak.

sql:
SELECT peaks.name, images.image_url, images.description
FROM peaks
LEFT JOIN images ON peaks.peak_id = images.peak_id;

SELECT name, description 
FROM peaks 
WHERE last_climbed = (SELECT MAX(last_climbed) FROM peaks);

SELECT p2.name, p2.difficulty
FROM peaks AS p1
JOIN peaks AS p2 ON p1.location_id = p2.location_id
WHERE p1.name = 'Mt Fuji' AND p2.difficulty > (
    SELECT difficulty FROM peaks WHERE name = 'Mt Fuji'
) AND p2.name != 'Mt Fuji';

SELECT AVG(difficulty) 
FROM peaks 
WHERE location_id = 1;
